// ============================================================
// Go To Top
// ============================================================
$(document).ready(function () {
    // hide #back-top first
    $("#back-top").hide();
    // fade in #back-top
    $(function () {
        $(window).scroll(function () {
            if ($(this).scrollTop() > 100) {
                $('#back-top').fadeIn();
            } else {
                $('#back-top').fadeOut();
            }
        });
        // scroll body to 0px on click
        $('#back-top a').click(function () {
            $('body,html').animate({
                scrollTop: 0
            }, 100);
            return false;
        });
    });
});

// ============================================================
//  Side Bar Menu
// ============================================================
$(document).ready(function () {
    $(".menu_icon").click(function () {
        $(".menu_icon").toggleClass("active");
    });
    $(".menu_icon").click(function () {
        $(".sidebar").toggleClass("active");
    });
    $(".menu_icon").click(function () {
        $(".mobile_menu").toggleClass("active");
    });
});

// ============================================================
// Side Bar Dropdown Menu
// ============================================================
$(document).ready(function () {
    $('.accordion .open').children('.accordion_content').slideDown();
    $('.accordion_headline').on('click', function () {
        var $this = $(this),
            $li = $this.closest('li'),
            $open = $this.closest('.accordion').find('li.open').not($li);

        //Close open accordions
        $open.children('.accordion_content').slideUp();
        $open.removeClass('open');

        //Open selected accordion
        $li.toggleClass('open');
        $this.next('.accordion_content').slideToggle();
    });
});

// ============================================================
// Desktop Dropdown Menu
// ============================================================
$(document).ready(function () {
    $(".dropdown_menu_toggle").click(function () {
        $(".dropdown_menus").slideToggle("slow");
    });
});

// ============================================================
// Modern Social Media Icon Display
// ============================================================
$(document).ready(function () {
    $(".share_icon").mouseover(function () {
        $(".social_icon").addClass("active");
    });
    $(".share_icon").mouseout(function () {
        $(".social_icon").removeClass("active");
    });
});

// ============================================================
// Owl Carousel
// ============================================================
$(document).ready(function () {
    $('#banner-slider').owlCarousel({
        loop: true,
        autoplay: true,
        autoplayTimeout: 7000,
        autoplayHoverPause: false,
        nav: false,
        dots: true,
        animateOut: 'fadeOut',
        animateIn: 'fadeIn',
        mouseDrag: true,
        touchDrag: true,
        responsive: {
            0: {
                items: 1
            },
            600: {
                items: 1
            },
            1000: {
                items: 1
            }
        }
    });

    $("#testimonials-slider").owlCarousel({
        loop: true,
        navigation: true,
        slideSpeed: 1400,
        paginationSpeed: 1000,
        navigationText: ["", ""],
        stopOnHover: true,
        autoHeight: true,
        mouseDrag: true,
        autoplay: false,
        autoplayTimeout: 3000,
        center: true,
        autoplayHoverPause: true,
        responsive: {
            0: {
                items: 1
            },
            480: {
                items: 1
            },
            768: {
                items: 1
            },
            992: {
                items: 1
            },
            1200: {
                items: 1
            }
        }
    });
    $("#team-slider").owlCarousel({
        loop: true,
        navigation: true,
        slideSpeed: 1400,
        paginationSpeed: 1000,
        navigationText: ["", ""],
        stopOnHover: true,
        autoHeight: true,
        mouseDrag: true,
        autoplay: false,
        autoplayTimeout: 3000,
        center: true,
        autoplayHoverPause: true,
        responsive: {
            0: {
                items: 1
            },
            480: {
                items: 2
            },
            768: {
                items: 3
            },
            992: {
                items: 3
            },
            1200: {
                items: 4
            }
        }
    });
});


