// ================================================================
// Sticky Header Bottom on Scroll
// ================================================================
(function () {
    var headerBottom = document.getElementById('header-bottom');
    var headerBottomWrapper = document.getElementById('header-bottom-wrapper');
    var spacer = document.getElementById('header-bottom-spacer');

    if (!headerBottom || !spacer) return;

    var stickyOffset = 0;

    function calcOffset() {
        // Temporarily remove sticky class to get original position
        headerBottom.classList.remove('header-bottom-sticky');
        if (headerBottomWrapper) headerBottomWrapper.classList.remove('header-bottom-sticky');
        spacer.style.display = 'none';
        stickyOffset = headerBottom.getBoundingClientRect().top + window.pageYOffset;
    }

    function handleScroll() {
        // Only apply on desktop (≥ 1100px)
        if (window.innerWidth < 1100) {
            headerBottom.classList.remove('header-bottom-sticky');
            if (headerBottomWrapper) headerBottomWrapper.classList.remove('header-bottom-sticky');
            spacer.style.display = 'none';
            return;
        }

        if (window.pageYOffset >= stickyOffset) {
            if (!headerBottomWrapper.classList.contains('header-bottom-sticky')) {
                spacer.style.height = headerBottom.offsetHeight + 'px';
                spacer.style.display = 'block';
                if (headerBottomWrapper) headerBottomWrapper.classList.add('header-bottom-sticky');
                headerBottom.classList.add('header-bottom-sticky');
            }
        } else {
            if (headerBottomWrapper) headerBottomWrapper.classList.remove('header-bottom-sticky');
            headerBottom.classList.remove('header-bottom-sticky');
            spacer.style.display = 'none';
        }
    }

    // Calculate once on load, then on resize
    window.addEventListener('load', function () {
        calcOffset();
        handleScroll();
    });

    window.addEventListener('resize', function () {
        calcOffset();
        handleScroll();
    });

    window.addEventListener('scroll', handleScroll, { passive: true });
})();



// BLOG PAGE
// JavaScript to handle swapping the blog post content
function swapBlog(clickedElement) {
    // Get main elements
    const mainBox = document.getElementById('main-blog');
    const mainImg = mainBox.querySelector('.main-img');
    const mainTitle = mainBox.querySelector('.main-title');
    const mainDesc = mainBox.querySelector('.main-desc');

    // Get clicked element details
    const clickedImgSrc = clickedElement.querySelector('.thumb-img').src;
    const clickedTitle = clickedElement.querySelector('.aside-title').textContent;
    // Full content is what goes into the main box body
    const clickedFullHTML = clickedElement.querySelector('.full-content').innerHTML;

    // Save current main details to swap back into the clicked element
    const tempImgSrc = mainImg.src;
    const tempTitle = mainTitle.textContent;
    const tempFullHTML = mainDesc.innerHTML;

    // Create a short description from the full HTML by stripping tags and truncating
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = tempFullHTML;
    let tempText = tempDiv.textContent || tempDiv.innerText || "";
    let tempShortDesc = tempText.trim().substring(0, 150);
    if (tempText.length > 150) tempShortDesc += '...';

    // Apply clicked element details to main box
    mainImg.src = clickedImgSrc;
    mainTitle.textContent = clickedTitle;
    mainDesc.innerHTML = clickedFullHTML;

    // Apply old main details to clicked element
    clickedElement.querySelector('.thumb-img').src = tempImgSrc;
    clickedElement.querySelector('.aside-title').textContent = tempTitle;
    clickedElement.querySelector('.aside-desc').textContent = tempShortDesc;
    clickedElement.querySelector('.full-content').innerHTML = tempFullHTML;

    // Optional: scroll slightly to the top of the main blog if on mobile
    if (window.innerWidth < 768) {
        mainBox.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
}


// faqs
document.addEventListener('DOMContentLoaded', function () {
    const faqHeaders = document.querySelectorAll('.faq-header');

    faqHeaders.forEach(header => {
        header.addEventListener('click', function (e) {
            e.preventDefault();

            // Get the target content ID #faq1, #faq2, etc.
            const targetId = this.getAttribute('data-target');
            if (!targetId) return;

            const targetContent = document.querySelector(targetId);
            if (!targetContent) return;

            // Toggle the header state (for icons)
            this.classList.toggle('collapsed');

            // Toggle the content visibility
            if (targetContent.classList.contains('show')) {
                targetContent.classList.remove('show');
                this.setAttribute('aria-expanded', 'false');
            } else {
                targetContent.classList.add('show');
                this.setAttribute('aria-expanded', 'true');
            }
        });
    });
});


// gallery inner

const filterBtns = document.querySelectorAll('.filter-btn');
const galleryItems = document.querySelectorAll('.gallery-item');
const categoryDesc = document.getElementById('category-desc');
const noResults = document.getElementById('no-results');

filterBtns.forEach(btn => {
    btn.addEventListener('click', () => {
        // update active button
        filterBtns.forEach(b => b.classList.remove('active'));
        btn.classList.add('active');

        const filter = btn.dataset.filter;
        const desc = btn.dataset.desc;

        // update description
        categoryDesc.style.opacity = '0';
        setTimeout(() => {
            categoryDesc.textContent = desc;
            categoryDesc.style.opacity = '1';
        }, 200);

        // filter cards
        let visibleCount = 0;
        galleryItems.forEach(item => {
            const cat = item.dataset.category;
            if (filter === 'all' || cat === filter) {
                item.classList.remove('hide');
                item.style.position = '';
                item.style.visibility = '';
                visibleCount++;
            } else {
                item.classList.add('hide');
            }
        });

        noResults.style.display = visibleCount === 0 ? 'block' : 'none';
    });
});